go的相关例子1.guess_unmberpackage mainimport (	&quot;fmt&quot;	&quot;math/rand&quot;	&quot;time&quot;)/**- 随机生成一个数字，输入一个数字看是否匹对，匹配则结速，反之提示是大了还是小了- 要求代码规范化- 每个函数不要超过80行，如果逻辑太复杂函数需要进行封装*/func main() &#123;	// 用户输入的数	var num int	// 随机生成的数	var rnum int	for true &#123;		rnum = randnum()		fmt.Println(&quot;输入一个0-100的数，看你是否猜对随机生成的数，输入-1退出&quot;)		fmt.Scanln(&amp;num)		//fmt.Printf(&quot;输入%d&quot;, rnum)		if num == -1 &#123;			return		&#125;		for rnum != num &#123;			if num &gt; rnum &#123;				fmt.Println(&quot;猜大了&quot;)			&#125; else if num &lt; rnum &#123;				fmt.Println(&quot;猜小了&quot;)			&#125;			fmt.Scanln(&amp;num)		&#125;		fmt.Println(&quot;恭喜，猜对了&quot;)	&#125;&#125;func randnum() int &#123;	rand.Seed(time.Now().Unix())	return rand.Intn(100)&#125;



2.tree.gopackage main/**- 输入tree.exe能够以树状的形式当前目录下所有文件*/import (	&quot;bufio&quot;	&quot;fmt&quot;	&quot;io/ioutil&quot;	&quot;os&quot;)func getPath(path string, indent string) &#123;	files, err := ioutil.ReadDir(path)	if err != nil &#123;		fmt.Println(&quot;read file path error&quot;, err)		return	&#125;	// 忽略以 . 开头的文件	for i := 0; i &lt; len(files); i++ &#123;		if files[i].Name()[0] == &#x27;.&#x27; &#123;			// 语法糖：...将一个切片或数组变成一个一个的元素,俗称将数组打散,用于append两个数组时			// ar[:n]等价于a[0:n] 即初始化为0			// ar[n:]等价于ar[n:len(ar)] 即默认为len(array/slice)			// append 追加			files = append(files[:i], files[i+1:]...)		&#125;	&#125;	// 创建文件名数组	dirs := make([]string, 0)	// 先打印文件	for _, fi := range files &#123;		if !fi.IsDir() &#123;			dirs = append(dirs, fi.Name())		&#125;	&#125;	// 记录文件个数	lenFile := len(dirs)	// 再打印文件夹	for _, fi := range files &#123;		if fi.IsDir() &#123;			dirs = append(dirs, fi.Name())		&#125;	&#125;	// 最后一个文件的分支用 └── 表示, 更美观	for i := 0; i &lt; len(dirs); i++ &#123;		if i == len(dirs)-1 &#123;			fmt.Println(indent + &quot;└── &quot; + dirs[i])			if i &gt;= lenFile &#123;				getPath(path+&quot;/&quot;+dirs[i], indent+&quot;   &quot;)			&#125;		&#125; else &#123;			fmt.Println(indent + &quot;├── &quot; + dirs[i])			if i &gt;= lenFile &#123;				getPath(path+&quot;/&quot;+dirs[i], indent+&quot;│  &quot;)			&#125;		&#125;	&#125;&#125;func main() &#123;	inputReader := bufio.NewReader(os.Stdin)	fmt.Println(&quot;输入tree.exe查看当前目录文件&quot;)	input, er := inputReader.ReadString(&#x27;\n&#x27;)	if er != nil &#123;		fmt.Println(&quot;read错误&quot;)		return	&#125;	switch input &#123;	// win下为 \r\n	case &quot;tree.exe\n&quot;:		exPath, err := os.Getwd() // 获取程序执行的当前路径		if err != nil &#123;			fmt.Println(&quot;路径错误&quot;)		&#125;		fmt.Println(&quot;\n当前运行目录：&quot;, exPath)		getPath(exPath, &quot;&quot;)	default:		fmt.Println(&quot;不支持其他输入&quot;)	&#125;&#125;



3.jjjbpackage main/**- 你有50枚⾦金金币，需要分配给以下⼏几个⼈人:- Matthew, Sarah, Augustus, Heidi, Emilie,Peter, Giana, Adriano, Aaron, Elizabeth。- 分配规则如下所示:- 名字中包含’a’或’A’: 1枚⾦金金币- 名字中包含’e’或’E’: 1枚⾦金金币- 名字中包含 ‘i’或’I’: 2枚⾦金金币- 名字中包含’o’或’O’: 3枚⾦金金币- 名字中包含’u’或’U’: 5枚⾦金金币写⼀一个程序，计算每个⽤用户分到了了多少⾦金金币，以及最后剩余多少⾦金金币?*/import (	&quot;fmt&quot;	&quot;strings&quot;)var (	coins = 50	users = []string&#123;		&quot;Matthew&quot;, &quot;Sarah&quot;, &quot;Augustus&quot;, &quot;Heidi&quot;, &quot;Emilie&quot;, &quot;Peter&quot;, &quot;Giana&quot;, &quot;Adriano&quot;, &quot;Aaron&quot;, &quot;Elizabeth&quot;,	&#125;	// map	distribution = make(map[string]int, len(users)))func main() &#123;	left := dispatchCoin()	fmt.Println(&quot;剩下：&quot;, left)	// 打印各自的jjjb	for _, name := range users &#123;		fmt.Printf(&quot;%s：%djjjb\n&quot;, name, distribution[name])	&#125;&#125;func dispatchCoin() int &#123;BREAK1:	for _, name := range users &#123;		// strings.ToLower()函数接收一个字符串，		// 并将字符串中的每个ASCII字符转换成小写，最后将新的字符串返回。		// strings.Split函数用于将指定的分隔符切割字符串		// 并返回切割后的字符串切片。		nameSlice := strings.Split(strings.ToLower(name), &quot;&quot;)		for _, word := range nameSlice &#123;			if coins == 0 &#123;				fmt.Println(&quot;jjjb不足&quot;)				break BREAK1			&#125;			switch word &#123;			case &quot;a&quot;, &quot;e&quot;:				if coins &gt;= 1 &#123;					distribution[name]++					coins--				&#125;			case &quot;i&quot;:				if coins &gt;= 2 &#123;					distribution[name] += 2					coins -= 2				&#125;			case &quot;o&quot;:				if coins &gt;= 3 &#123;					distribution[name] += 3					coins -= 3				&#125;			case &quot;u&quot;:				if coins &gt;= 5 &#123;					distribution[name] += 5					coins -= 5				&#125;			&#125;		&#125;	&#125;	return coins&#125;
